// ============================================================
// AUDIO MANAGER
// - Chỉ 1 Audio instance duy nhất mỗi loại, không bao giờ chồng nhạc
// - API: AudioManager.playMenuMusic() | startGameMusic() | stopGameMusic()
// ============================================================
const AudioManager = (() => {
  const _menu = new Audio("menu.mp3");
  _menu.loop   = true;
  _menu.volume = 1;

  const _game = new Audio("music.mp3");
  _game.loop   = true;
  _game.volume = 1;

  // Trình duyệt chặn autoplay — lưu cờ, phát ngay sau gesture đầu tiên
  let _ready   = false;
  let _pending = false;

  function _onGesture() {
    _ready = true;
    if (_pending) { _pending = false; _menu.play().catch(() => {}); }
  }
  ['click', 'keydown', 'touchstart'].forEach(e =>
    document.addEventListener(e, _onGesture, { once: true })
  );

  /** showMenu / gameOver → phát nhạc menu từ đầu */
  function playMenuMusic() {
    _game.pause(); _game.currentTime = 0;
    _menu.currentTime = 0;
    if (_ready) { _menu.play().catch(() => {}); }
    else { _pending = true; }
  }

  /** startGame → dừng menu NGAY, phát nhạc gameplay */
  function startGameMusic() {
    _menu.pause(); _menu.currentTime = 0;
    _pending = false;
    _game.currentTime = 0;
    _game.play().catch(() => {});
  }

  /** Dừng nhạc gameplay */
  function stopGameMusic() {
    _game.pause(); _game.currentTime = 0;
  }

  return { playMenuMusic, startGameMusic, stopGameMusic };
})();

// Phát nhạc menu ngay khi trang load
AudioManager.playMenuMusic();

// Shim cho code cũ vẫn dùng biến backgroundMusic
const backgroundMusic = {
  pause()           { AudioManager.stopGameMusic();  },
  play()            { AudioManager.startGameMusic(); },
  get currentTime() { return 0; },
  set currentTime(_){ }
};

