// ============================================================
// PRELOAD IMAGES
// ============================================================
const loadedImages = {};

function loadImage(id) {
  if (loadedImages[id]) return loadedImages[id];
  const img = new Image();
  img.src = ASSETS[id];
  loadedImages[id] = img;
  return img;
}

function preloadAll() {
  const allIds = [
    IMG.backdrop, IMG.mortyBody, IMG.mortyNet, IMG.mortyWrong, IMG.ocean, IMG.gameOver, IMG.scorecard, IMG.thumb,
    ...Object.values(IMG.rubbish),
    ...Object.values(IMG.marine),
  ];
  allIds.forEach(id => loadImage(id));
}

// ============================================================
// AUDIO
// ============================================================
function playSound(id) {
  try {
    const audio = new Audio(ASSETS[id]);
    audio.volume = 1;
    audio.play().catch(()=>{});
  } catch(e) {}
}

// ============================================================
// GAME STATE
// ============================================================
const canvas = document.getElementById('gameCanvas');
const ctx = canvas.getContext('2d');

const W = 480, H = 360;

const RUBBISH_TYPES = Object.entries(IMG.rubbish).map(([name, id]) => ({ name, id, isRubbish: true }));
const MARINE_TYPES  = Object.entries(IMG.marine).map(([name, id])  => ({ name, id, isRubbish: false }));
const ALL_TYPES = [...RUBBISH_TYPES, ...MARINE_TYPES];

let state = 'start'; // 'start' | 'playing' | 'gameover'
let score = 0;
let lives = 3;
let mortyX = W / 2;
let mortyY = H - 55;
let mortyWrong = false;
let mortyWrongTimer = 0;
let items = [];
let particles = [];
let spawnTimer = 0;
let spawnInterval = 90; // frames
let gameFrame = 0;
let speed = 2.5;
let mouseX = W / 2;

// Controls
const keys = { left: false, right: false };

// ============================================================
// ITEM CLASS
// ============================================================
class FallingItem {
  constructor() {
    const type = ALL_TYPES[Math.floor(Math.random() * ALL_TYPES.length)];
    this.name = type.name;
    this.id = type.id;
    this.isRubbish = type.isRubbish;
    this.x = 30 + Math.random() * (W - 60);
    this.y = -30;
    this.size = 36 + Math.random() * 16;
    this.vx = (Math.random() - 0.5) * 1.2;
    this.vy = speed + Math.random() * 1.5;
    this.rotation = Math.random() * Math.PI * 2;
    this.rotSpeed = (Math.random() - 0.5) * 0.08;
    this.wobble = Math.random() * Math.PI * 2;
    this.alive = true;
    this.caught = false;
  }

  update() {
    this.y += this.vy;
    this.x += this.vx;
    this.rotation += this.rotSpeed;
    this.wobble += 0.05;
    this.x += Math.sin(this.wobble) * 0.3;
    if (this.y > H + 40) this.alive = false;
    if (this.x < -30 || this.x > W + 30) this.alive = false;
  }

  draw(ctx) {
    const img = loadedImages[this.id];
    if (!img || !img.complete) return;
    ctx.save();
    ctx.translate(this.x, this.y);
    ctx.rotate(this.rotation);
    const s = this.size;
    ctx.drawImage(img, -s/2, -s/2, s, s);
    ctx.restore();
  }
}

// ============================================================
// PARTICLE
// ============================================================
class Particle {
  constructor(x, y, color, emoji) {
    this.x = x;
    this.y = y;
    this.vx = (Math.random() - 0.5) * 5;
    this.vy = -3 - Math.random() * 4;
    this.alpha = 1;
    this.color = color;
    this.emoji = emoji;
    this.size = 16 + Math.random() * 12;
    this.life = 40;
  }

  update() {
    this.x += this.vx;
    this.y += this.vy;
    this.vy += 0.2;
    this.life--;
    this.alpha = this.life / 40;
  }

  draw(ctx) {
    ctx.save();
    ctx.globalAlpha = this.alpha;
    if (this.emoji) {
      ctx.font = `${this.size}px serif`;
      ctx.textAlign = 'center';
      ctx.fillText(this.emoji, this.x, this.y);
    } else {
      ctx.fillStyle = this.color;
      ctx.font = `bold ${this.size}px 'Fredoka One', cursive`;
      ctx.textAlign = 'center';
      ctx.fillText(this.color === '#ff4466' ? '-1 ❤️' : `+10`, this.x, this.y);
    }
    ctx.restore();
  }
}

// ============================================================
// SPAWN ITEMS
// ============================================================
function spawnItem() {
  items.push(new FallingItem());
}

// ============================================================
// COLLISION
// ============================================================
function checkCollision(item) {
  const dx = item.x - mortyX;
  const dy = item.y - mortyY;
  const dist = Math.sqrt(dx*dx + dy*dy);
  return dist < (item.size / 2 + 28);
}

// ============================================================
// UPDATE SCORE/LIVES HUD
// ============================================================
function updateHUD() {
  document.getElementById('score-display').textContent = score;
  const livesEl = document.getElementById('lives-display');
  livesEl.innerHTML = '';
  for (let i = 0; i < 3; i++) {
    const h = document.createElement('span');
    h.className = 'heart';
    h.textContent = i < lives ? '❤️' : '🖤';
    livesEl.appendChild(h);
  }
}

// ============================================================
// GAME LOOP
// ============================================================
function gameLoop() {
  if (state !== 'playing') return;

  ctx.clearRect(0, 0, W, H);

  // Draw background
  const bg = loadedImages[IMG.backdrop];
  if (bg && bg.complete) ctx.drawImage(bg, 0, 0, W, H);

  // Draw ocean overlay
  const ocean = loadedImages[IMG.ocean];
  if (ocean && ocean.complete) {
    ctx.globalAlpha = 0.9;
    ctx.drawImage(ocean, 0, H * 0.45, W, H * 0.55);
    ctx.globalAlpha = 1;
  }

  gameFrame++;

  // Move Morty
  const speed_px = 5;
  if (keys.left)  mortyX = Math.max(20, mortyX - speed_px);
  if (keys.right) mortyX = Math.min(W - 20, mortyX + speed_px);

  // Smooth to mouse
  if (!keys.left && !keys.right) {
    const targetX = Math.max(20, Math.min(W - 20, mouseX));
    mortyX += (targetX - mortyX) * 0.12;
  }

  // Spawn items
  spawnTimer++;
  if (spawnTimer >= spawnInterval) {
    spawnTimer = 0;
    spawnItem();
    if (Math.random() < 0.4) spawnItem(); // Sometimes spawn two
    // Gradually increase difficulty
    spawnInterval = Math.max(35, 90 - Math.floor(gameFrame / 120));
    speed = 2.5 + gameFrame / 600;
  }

  // Update & draw items
  for (let i = items.length - 1; i >= 0; i--) {
    const item = items[i];
    item.vy = speed + (item.vy - speed) * 0.95; // Smooth speed transition
    item.update();

    if (!item.alive) {
      items.splice(i, 1);
      continue;
    }

    // Collision check
    if (checkCollision(item)) {
      item.alive = false;
      items.splice(i, 1);

      if (item.isRubbish) {
        score += 10;
        updateHUD();
        playSound(SND.pop);
        for (let p = 0; p < 5; p++) {
          particles.push(new Particle(item.x, item.y, '#00ff88', '✨'));
        }
        particles.push(new Particle(mortyX, mortyY - 20, '#ffd700', null));
      } else {
        lives--;
        updateHUD();
        mortyWrong = true;
        mortyWrongTimer = 45;
        playSound(SND.wrong);
        for (let p = 0; p < 4; p++) {
          particles.push(new Particle(item.x, item.y, '#ff4466', '💔'));
        }
        particles.push(new Particle(mortyX, mortyY - 20, '#ff4466', null));

        if (lives <= 0) {
          setTimeout(() => endGame(), 400);
        }
      }
      continue;
    }

    item.draw(ctx);
  }

  // Draw Morty
  mortyWrongTimer--;
  if (mortyWrongTimer <= 0) mortyWrong = false;

  const mortyImg = mortyWrong
    ? loadedImages[IMG.mortyWrong]
    : loadedImages[IMG.mortyBody];

  const netImg = loadedImages[IMG.mortyNet];

  // Draw net first (behind body)
  if (netImg && netImg.complete) {
    ctx.drawImage(netImg, mortyX - 28, mortyY - 20, 56, 40);
  }
  if (mortyImg && mortyImg.complete) {
    ctx.save();
    if (mortyWrong) {
      ctx.globalAlpha = 0.85 + 0.15 * Math.sin(gameFrame * 0.5);
    }
    ctx.drawImage(mortyImg, mortyX - 24, mortyY - 30, 48, 56);
    ctx.restore();
  }

  // Draw particles
  for (let i = particles.length - 1; i >= 0; i--) {
    particles[i].update();
    particles[i].draw(ctx);
    if (particles[i].life <= 0) particles.splice(i, 1);
  }

  // Score flash
  if (gameFrame % 300 === 0 && score > 0) {
    const el = document.getElementById('score-display');
    el.style.transform = 'scale(1.4)';
    el.style.color = '#ffd700';
    setTimeout(() => {
      el.style.transform = '';
      el.style.color = '';
    }, 300);
  }

  requestAnimationFrame(gameLoop);
}

// ============================================================
// GAME OVER
// ============================================================
function endGame() {
  // ── Guard: chỉ chạy khi đang playing ──
  if (state !== 'playing') return;

  backgroundMusic.pause();
  backgroundMusic.currentTime = 0;

  // Phát lại nhạc menu khi game over
  AudioManager.stopGameMusic();
  AudioManager.playMenuMusic();

  document.getElementById("overlay-gameover").classList.remove("hidden");

  state = 'gameover';
  playSound(SND.lose);

  const msgs = [
    "Mẹo: Hãy di chuyển nhanh, đừng Alo Vũ à em",
    "Mẹo: Né sinh vật biển ra",
    "Mẹo: Mày Bé",
    "Alo Vũ à em!",
    "Ờ anh chào Vũ nhé, em là Vũ à Vũ"
  ];
  const msg = msgs[Math.floor(Math.random() * msgs.length)];

  document.getElementById('final-score').textContent = `Score: ${score}`;
  document.getElementById('gameover-msg').textContent = msg;
  document.getElementById('overlay-gameover').classList.remove('hidden');
}

// ============================================================
// START / RESTART
// ============================================================
function startGame() {
  // ── Reset toàn bộ state ──
  state = 'playing';
  score = 0;
  lives = 3;
  items = [];
  particles = [];
  spawnTimer = 0;
  spawnInterval = 90;
  speed = 2.5;
  gameFrame = 0;
  mortyX = W / 2;
  mortyWrong = false;
  mortyWrongTimer = 0;

  updateHUD();

  // ── Ẩn cả hai overlay ──
  document.getElementById('overlay').classList.add('hidden');
  document.getElementById('overlay-gameover').classList.add('hidden');

  // Dừng nhạc menu ngay lập tức, phát nhạc gameplay
  AudioManager.startGameMusic();

  // ── Khởi chạy game loop (chỉ 1 loop, không duplicate) ──
  requestAnimationFrame(gameLoop);
}

// ============================================================
// INPUT
// ============================================================
window.addEventListener('keydown', e => {
  if (e.key === 'ArrowLeft'  || e.key === 'a') keys.left  = true;
  if (e.key === 'ArrowRight' || e.key === 'd') keys.right = true;
});
window.addEventListener('keyup', e => {
  if (e.key === 'ArrowLeft'  || e.key === 'a') keys.left  = false;
  if (e.key === 'ArrowRight' || e.key === 'd') keys.right = false;
});

canvas.addEventListener('mousemove', e => {
  const rect = canvas.getBoundingClientRect();
  mouseX = (e.clientX - rect.left) * (W / rect.width);
});

// Touch support
canvas.addEventListener('touchmove', e => {
  e.preventDefault();
  const rect = canvas.getBoundingClientRect();
  mouseX = (e.touches[0].clientX - rect.left) * (W / rect.width);
}, { passive: false });

document.getElementById('start-btn').addEventListener('click', startGame);
document.getElementById('restart-btn').addEventListener('click', startGame);

// ============================================================
// DRAW IDLE BACKGROUND (before game starts)
// ============================================================
function drawIdleBackground() {
  const bg = loadedImages[IMG.backdrop];
  if (bg && bg.complete) {
    ctx.drawImage(bg, 0, 0, W, H);
  } else {
    ctx.fillStyle = '#0a3d6b';
    ctx.fillRect(0, 0, W, H);
  }
}

// ============================================================
// INIT
// ============================================================
preloadAll();
setTimeout(drawIdleBackground, 300);
